storage_virtual_machines = {
    ex-basic = {
      name = "basic"

      volumes = {
        ex-basic = {
          name                       = "basic"
          junction_path              = "/test"
          size_in_megabytes          = 1024
          storage_efficiency_enabled = true
        }
      }
    }
    ex-flexgroup = {
      name = "flexgroup"

      volumes = {
        ex-flexgroup = {
          name                       = "flexgroup"
          junction_path              = "/test"
          size_in_bytes              = 1024000000000
          storage_efficiency_enabled = true
          volume_style               = "FLEXGROUP"
          aggregate_configuration = {
            constituents_per_aggregate = 9
          }
        }
      }
    }
    ex-other = {
      name                       = "one"
      root_volume_security_style = "NTFS"
      svm_admin_password         = "avoid-plaintext-passwords1"

      volumes = {
        ex-other = {
          name                       = "other"
          junction_path              = "/test"
          size_in_megabytes          = 1024
          storage_efficiency_enabled = true

          tiering_policy = {
            name           = "AUTO"
            cooling_period = 31
          }
        }
        ex-snaplock = {
          name                       = "snaplock"
          junction_path              = "/snaplock_audit_log"
          size_in_megabytes          = 1024
          storage_efficiency_enabled = true

          bypass_snaplock_enterprise_retention = true
          snaplock_configuration = {
            audit_log_volume           = true
            privileged_delete          = "PERMANENTLY_DISABLED"
            snaplock_type              = "ENTERPRISE"
            volume_append_mode_enabled = false

            autocommit_period = {
              type  = "DAYS"
              value = 14
            }

            retention_period = {
              default_retention = {
                type  = "DAYS"
                value = 30
              }

              maximum_retention = {
                type  = "MONTHS"
                value = 9
              }

              minimum_retention = {
                type  = "HOURS"
                value = 24
              }
            }
          }
        }
      }
    }
    ex-active-directory = {
      active_directory_configuration = {
        netbios_name = "mysvm"
        self_managed_active_directory_configuration = {
          dns_ips     = aws_directory_service_directory.this.dns_ip_addresses
          domain_name = aws_directory_service_directory.this.name
          password    = aws_directory_service_directory.this.password
          username    = "Admin"
        }
      }

      volumes = {
        ex-snaplock-ent = {
          name                       = "snaplock_ent"
          junction_path              = "/log"
          size_in_megabytes          = 1024
          storage_efficiency_enabled = true

          bypass_snaplock_enterprise_retention = true
          snaplock_configuration = {
            snaplock_type = "ENTERPRISE"
          }
        }
      }
    }
  }

root_volume_configuration = {
    copy_tags_to_snapshots = true
    data_compression_type  = "LZ4"

    nfs_exports = {
      client_configurations = [
        {
          clients = "10.0.1.0/24"
          options = ["async", "rw"]
        },
        {
          clients = "*"
          options = ["sync", "rw"]
        }
      ]
    }

    read_only       = false
    record_size_kib = 128

    user_and_group_quotas = [
      {
        id                         = 0
        storage_capacity_quota_gib = 128
        type                       = "GROUP"
      },
      {
        id                         = 0
        storage_capacity_quota_gib = 64
        type                       = "USER"
      },
    ]
  }

